                  {Math.max(0, (NEXT_THRESHOLD[word.status] ?? 100) - (word.confidenceScore ?? 0))} pts to {STATUS_META[NEXT_STATUS[word.status]!].label}
                </div>
              </div>
            )}
            {word.status === 'mastered' && <div style={{ marginBottom: '20px' }} />}
            <div style={{ display: 'grid', gap: '12px' }}>
