export default function ChatSession({ isActive, onEndSession, pendingPrompt, clearPrompt, isSandboxMode }: Props) {
  const { vocabulary, concepts, studentName, bio, activeCurriculumId, activeModuleId, curriculums, applyScoreDeltas } = useMasteryStore();
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const dragControls = useDragControls();

  const historyRef      = useRef<{ role: 'user' | 'assistant'; content: string }[]>([]);
  // Accumulates every proposed delta from all assistant turns this session.
  const accumulatedRef = useRef<ProposedChange[]>([]);

  const curriculum = curriculums.find(c => c.id === activeCurriculumId);
  const module     = curriculum?.modules.find(m => m.id === activeModuleId);

  // Re-run system prompt build if store or lesson changes.
  const sys = buildSystemPrompt(
    vocabulary,
    concepts,
    studentName,
    bio,
    curriculum?.title,
    module?.title
  );

  useEffect(() => {
    if (pendingPrompt) {
      const key = resolveApiKey();
      sendToLina(pendingPrompt, key);
      clearPrompt();
    }
  }, [pendingPrompt, clearPrompt]);

  async function handleEndSession() {
    const key = resolveApiKey();
    const deltas = accumulatedRef.current;

    if (deltas.length === 0 || !key || isSandboxMode) {
      onEndSession();
      return;
    }

    setIsLoading(true);
    // Add a placeholder message for the recap.
    const assistantId = crypto.randomUUID();
    setMessages(prev => [...prev, {
      id: assistantId,
      role: 'assistant',
      displayContent: 'Wrapping up our session...',
      raw: ''
    }]);

    try {
      // fetches a plain-language recap before dismissing.
      const recap = await fetchSessionRecap(key, deltas);
      setMessages(prev => prev.map(msg =>
        msg.id === assistantId
          ? { ...msg, displayContent: recap, raw: recap }
          : msg
      ));

      // Actually apply the changes to the store.
      const scoreDeltas = deltas
        .filter(d => d.type === 'vocab')
        .map(d => ({ wordId: d.id, delta: 10 })); // increment slightly for demo
      applyScoreDeltas(scoreDeltas);

      // Wait a moment so the student can read the recap.
      await new Promise(r => setTimeout(r, 2200));
    } catch (e) {
      console.error('Session end error:', e);
    } finally {
      setIsLoading(false);
      onEndSession();
      // Clean up local history for the next session.
      historyRef.current = [];
      accumulatedRef.current = [];
      setMessages([]);
    }
  }

  async function sendToLina(txt: string, overrideKey?: string) {
    if (!txt.trim() || isLoading) return;
    const key = overrideKey || resolveApiKey();

    const userMsg: Message = { id: crypto.randomUUID(), role: 'user', displayContent: txt, raw: txt };
    setMessages(prev => [...prev, userMsg]);
    historyRef.current.push({ role: 'user', content: txt });
    setInput('');

    if (!key && !isSandboxMode) return;

    setIsLoading(true);
    const assistantId = crypto.randomUUID();
    setMessages(prev => [...prev, { id: assistantId, role: 'assistant', displayContent: '', raw: '' }]);

    let full = '';
    try {
      if (isSandboxMode) {
        await new Promise(r => setTimeout(r, 800));
        full = SANDBOX_RESPONSE;
        setMessages(prev => prev.map(msg =>
          msg.id === assistantId
            ? { ...msg, displayContent: stripProposedChanges(full), raw: full }
            : msg
        ));
        historyRef.current.push({ role: 'assistant', content: SANDBOX_RESPONSE });
      } else {
        const windowedHistory = historyRef.current.slice(-10);
        for await (const chunk of streamCompletion(key, sys, windowedHistory)) {
          full += chunk;
          setMessages(prev => prev.map(msg =>
            msg.id === assistantId ? { ...msg, displayContent: stripProposedChanges(full), raw: full } : msg
          ));
        }

        const changes = parseProposedChanges(full);
        if (changes) {
          accumulatedRef.current = [...accumulatedRef.current, ...changes];
          setMessages(prev => prev.map(msg =>
            msg.id === assistantId ? { ...msg, proposedChanges: changes } : msg
          ));
        }
        historyRef.current.push({ role: 'assistant', content: full });
      }
    } catch (e: any) {
      full = `Sorry, I hit an error: ${e.message}`;
      setMessages(prev => prev.map(msg =>
        msg.id === assistantId
          ? { ...msg, displayContent: full, raw: full }
          : msg
      ));
    } finally {
      setIsLoading(false);
    }
  }

  return (
    <AnimatePresence>
      {isActive && (
        <motion.div
          key="backdrop"
          className="drawer-backdrop"
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          onClick={handleEndSession}
          style={{ zIndex: 1999 }}
        />
      )}
      {isActive && (
        <motion.div
          key="chat-drawer"
          className="chat-drawer"
          drag="y"
          dragControls={dragControls}
          dragListener={false}
          dragConstraints={{ top: 0 }}
          onDragEnd={(_, info) => { if (info.offset.y > 100) handleEndSession(); }}
          initial={{ y: '100%' }}
          animate={{ y: 0 }}
          exit={{ y: '100%' }}
          style={{ zIndex: 2000 }}
        >
          <div
            style={{ padding: '12px 0 6px', cursor: 'grab', touchAction: 'none' }}
            onPointerDown={(e) => dragControls.start(e)}
          >
            <div className="drawer__handle" style={{ margin: '0 auto' }} />
          </div>

          <div style={{ padding: '0 20px 10px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', borderBottom: '1px solid #222' }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
              <div style={{ width: '8px', height: '8px', borderRadius: '50%', background: isLoading ? '#f59e0b' : '#10b981' }} />
              <span style={{ fontSize: '0.7rem', fontWeight: 900, letterSpacing: '0.1em', color: '#666' }}>
                CHAT WITH JAN LINA
              </span>
            </div>
            <button onClick={handleEndSession} style={{ background: 'none', border: 'none', color: '#888', fontSize: '1.2rem', cursor: 'pointer' }}>✕</button>
          </div>

          <div style={{ flex: 1, overflowY: 'auto', padding: '20px', display: 'flex', flexDirection: 'column', gap: '20px' }}>
            {messages.length === 0 && (
              <div style={{ textAlign: 'center', marginTop: '40px' }}>
                <div style={{ fontSize: '2.5rem', marginBottom: '16px' }}>💬</div>
                <div style={{ color: '#fff', fontWeight: 'bold', marginBottom: '8px' }}>toki jan Lina!</div>
                <div style={{ color: '#666', fontSize: '0.9rem', maxWidth: '240px', margin: '0 auto' }}>
                  {!resolveApiKey() && !isSandboxMode ? 'Please set your API Key in Settings to chat with jan Lina.' : 'Say hi to start practicing Toki Pona.'}
                </div>
              </div>
            )}
