  const prompt = `Act as jan Lina, a Toki Pona tutor. Given these words: [${words.join(', ')}], generate 3 short grammatically correct Toki Pona sentences using most or all of them.${bioInstruction} Provide English translations. You MAY add particles like "li", "e", "en", "la", or "pi". Return a JSON array of strings: ["sentence 1 (translation)", "sentence 2 (translation)", "sentence 3 (translation)"]`;
  try {
    const result = await model.generateContent(prompt);
    return JSON.parse(sanitizeJson(result.response.text())) as string[];
  } catch (e) {
    console.error('jan Lina Suggestion Error:', e);
    return [];
  }
}

