  const dragControls = useDragControls();

  const historyRef      = useRef<{ role: 'user' | 'assistant'; content: string }[]>([]);
  // Accumulates every proposed delta from all assistant turns this session.
  const accumulatedRef = useRef<ProposedChange[]>([]);

  const curriculum = curriculums.find(c => c.id === activeCurriculumId);
  const module     = curriculum?.modules.find(m => m.id === activeModuleId);

  // Re-run system prompt build if store or lesson changes.
  const sys = buildSystemPrompt(
    vocabulary,
    concepts,
    studentName,
    curriculum?.title,
    module?.title
  );

  useEffect(() => {
    if (pendingPrompt) {
      const key = resolveApiKey();
      sendToLina(pendingPrompt, key);
      clearPrompt();
    }
  }, [pendingPrompt, clearPrompt]);

  async function handleEndSession() {
    const key = resolveApiKey();
    const deltas = accumulatedRef.current;

    if (deltas.length === 0 || !key || isSandboxMode) {
      onEndSession();
      return;
    }

    setIsLoading(true);
    // Add a placeholder message for the recap.
    const assistantId = crypto.randomUUID();
    setMessages(prev => [...prev, {
      id: assistantId,
      role: 'assistant',
      displayContent: 'Wrapping up our session...',
      raw: ''
    }]);

    try {
      // fetches a plain-language recap before dismissing.
      const recap = await fetchSessionRecap(key, deltas);
      setMessages(prev => prev.map(msg =>
        msg.id === assistantId
          ? { ...msg, displayContent: recap, raw: recap }
          : msg
      ));

      // Actually apply the changes to the store.
      const scoreDeltas = deltas
        .filter(d => d.type === 'vocab')
        .map(d => ({ wordId: d.id, delta: 10 })); // increment slightly for demo
      applyScoreDeltas(scoreDeltas);

      // Wait a moment so the student can read the recap.
      await new Promise(r => setTimeout(r, 2200));
    } catch (e) {
      console.error('Session end error:', e);
    } finally {
      setIsLoading(false);
      onEndSession();
      // Clean up local history for the next session.
      historyRef.current = [];
      accumulatedRef.current = [];
      setMessages([]);
    }
  }

  async function sendToLina(txt: string, overrideKey?: string) {
    if (!txt.trim() || isLoading) return;
    const key = overrideKey || resolveApiKey();

    const userMsg: Message = { id: crypto.randomUUID(), role: 'user', displayContent: txt, raw: txt };
    setMessages(prev => [...prev, userMsg]);
    historyRef.current.push({ role: 'user', content: txt });
    setInput('');

    if (!key && !isSandboxMode) return;

    setIsLoading(true);
    const assistantId = crypto.randomUUID();
    setMessages(prev => [...prev, { id: assistantId, role: 'assistant', displayContent: '', raw: '' }]);

    let full = '';
    try {
      if (isSandboxMode) {
        await new Promise(r => setTimeout(r, 800));
        full = SANDBOX_RESPONSE;
        setMessages(prev => prev.map(msg =>
          msg.id === assistantId
            ? { ...msg, displayContent: stripProposedChanges(full), raw: full }
            : msg
        ));
        historyRef.current.push({ role: 'assistant', content: SANDBOX_RESPONSE });
