            <textarea
              value={bio}
              onChange={(e) => setBio(e.target.value)}
              placeholder="e.g. I like cooking, I live in Canada, I'm a software engineer..."
              style={{
                width: '100%',
                height: '100px',
                background: '#1a1a1a',
                border: '1px solid #333',
                borderRadius: '12px',
                padding: '12px',
                color: 'white',
                fontSize: '0.9rem',
                fontFamily: 'inherit',
                resize: 'none',
                outline: 'none',
                transition: 'border-color 0.2s'
              }}
              onFocus={(e) => e.currentTarget.style.borderColor = '#3b82f6'}
              onBlur={(e) => e.currentTarget.style.borderColor = '#333'}
            />
          </div>

          <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
