import { motion, AnimatePresence } from 'framer-motion';
import { useEffect, useState } from 'react';
import { useMasteryStore } from '../store/masteryStore';
import { STATUS_META } from '../types/mastery';
import type { VocabWord, MasteryStatus } from '../types/mastery';
import { fetchExamplesForWord, resolveApiKey } from '../services/linaService';

const TIER_RANGES: Record<MasteryStatus, [number, number]> = {
  not_started: [0,  19],
  introduced:  [20, 39],
  practicing:  [40, 64],
  confident:   [65, 84],
  mastered:    [85, 100],
};
const NEXT_STATUS: Partial<Record<MasteryStatus, MasteryStatus>> = {
  not_started: 'introduced',
  introduced:  'practicing',
  practicing:  'confident',
  confident:   'mastered',
};
const NEXT_THRESHOLD: Partial<Record<MasteryStatus, number>> = {
  not_started: 20, introduced: 40, practicing: 65, confident: 85,
};
const NEXT_COLOR: Record<MasteryStatus, string> = {
  not_started: '#1d4ed8',
  introduced:  '#92400e',
  practicing:  '#16a34a',
  confident:   '#22c55e',
  mastered:    '#22c55e',
};

// Common phrases for core words — a few hardcoded examples as requested.
const CORE_COMMON_PHRASES: Record<string, string[]> = {
  'pona': ['ale li pona.', 'toki pona.', 'sina pona.'],
  'ike': ['mi pilin ike.', 'ni li ike.', 'ike mute!'],
  'moku': ['mi moku.', 'moku li pona.', 'sina moku e telo.'],
  'toki': ['mi toki tawa sina.', 'toki!', 'toki pona li musi.'],
  'pali': ['mi pali e ni.', 'pali pona!', 'sina pali mute.'],
  'sona': ['mi sona.', 'sina sona mute.', 'jan pi sona mute.'],
  'lukin': ['mi lukin e ni.', 'lukin pona!', 'sina lukin e sitelen.'],
  'wile': ['mi wile moku.', 'sina wile e seme?', 'mi wile pali.'],
};

function tierProgress(score: number, status: MasteryStatus): number {
  const [lo, hi] = TIER_RANGES[status];
  return Math.min(1, Math.max(0, (score - lo) / (hi - lo)));
}

export default function WordDetailDrawer({ isOpen, word, onClose, onAskLina, isSandboxMode }: { isOpen: boolean; word?: VocabWord | null; onClose: () => void; onAskLina: (p: string) => void; isSandboxMode: boolean }) {
  const { cycleWordStatus, bio } = useMasteryStore();
  const [linaExamples, setLinaExamples] = useState<Record<string, string> | null>(null);
  const [isLoadingExamples, setIsLoadingExamples] = useState(false);

  const partsOfSpeech = word?.partOfSpeech?.split('/').map(p => p.trim()) ?? [];
  const primaryMeaning = word?.meanings?.split(',')[0].trim() || word?.meanings;
  const commonPhrases = word ? CORE_COMMON_PHRASES[word.word] || [] : [];

  useEffect(() => {
    if (isOpen && word) {
      setLinaExamples(null);
      const key = resolveApiKey();
      if (key && !isSandboxMode) {
        setIsLoadingExamples(true);
        fetchExamplesForWord(key, word.word, partsOfSpeech, bio)
          .then(setLinaExamples)
          .finally(() => setIsLoadingExamples(false));
      }
    }
  }, [isOpen, word, isSandboxMode, bio, partsOfSpeech]);

  return (
    <AnimatePresence>
      {isOpen && word && (
        <motion.div 
          key="backdrop" 
          className="drawer-backdrop" 
          initial={{ opacity: 0 }} 
          animate={{ opacity: 1 }} 
          exit={{ opacity: 0 }} 
          onClick={onClose} 
        />
      )}
      {isOpen && word && (
        <motion.div 
          key="drawer" 
          className="word-drawer" 
          initial={{ opacity: 0, scale: 0.95 }} 
          animate={{ opacity: 1, scale: 1 }} 
          exit={{ opacity: 0, scale: 0.95 }} 
          onClick={(e) => e.stopPropagation()}
          transition={{ type: 'spring', damping: 25, stiffness: 300 }}
        >
          <div className="drawer__handle" />
          <div className="drawer__scroll-area">
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '8px' }}>
              <div>
                <h2 style={{ fontSize: '2.4rem', marginBottom: '4px' }}>{word.word}</h2>
                <div style={{ fontSize: '1.1rem', color: '#888', fontWeight: 600 }}>{primaryMeaning}</div>
              </div>
              <button 
                onClick={() => cycleWordStatus(word.id)}
                className="btn-toggle"
                style={{ flex: 'none', background: '#222', color: '#fff', border: '1px solid #444', padding: '8px 12px', fontSize: '0.65rem' }}
              >
                QUICK CYCLE
              </button>
            </div>

            <div
              style={{ color: '#888', marginBottom: '10px', fontSize: '0.8rem', fontWeight: 'bold' }}
            >
              {STATUS_META[word.status].emoji} {STATUS_META[word.status].label.toUpperCase()}
            </div>

            {/* Confidence progress bar — shows position within current tier */}
            {word.status !== 'mastered' && (
              <div style={{ marginBottom: '24px' }}>
                <div className="progress-bar-track">
                  <div
                    className="progress-bar-fill"
                    style={{
                      width: `${tierProgress(word.confidenceScore ?? 0, word.status) * 100}%`,
                      background: NEXT_COLOR[word.status],
                    }}
                  />
                </div>
                <div style={{ fontSize: '0.65rem', color: '#555', marginTop: '4px', fontWeight: 700 }}>
                  {Math.max(0, (NEXT_THRESHOLD[word.status] ?? 100) - (word.confidenceScore ?? 0))} pts to {STATUS_META[NEXT_STATUS[word.status]!].label}
                </div>
              </div>
            )}
            {word.status === 'mastered' && <div style={{ marginBottom: '24px' }} />}

            {commonPhrases.length > 0 && (
              <div style={{ marginBottom: '24px' }}>
                <h3 className="section-title" style={{ marginBottom: '12px' }}>Common Phrases</h3>
                <div style={{ display: 'flex', flexWrap: 'wrap', gap: '8px' }}>
                  {commonPhrases.map(p => (
                    <div 
                      key={p}
                      onClick={() => onAskLina(`Let's practice: "${p}"`)}
                      style={{ background: '#111', border: '1px solid #222', padding: '8px 12px', borderRadius: '8px', fontSize: '0.85rem', color: '#ccc', cursor: 'pointer' }}
                    >
                      {p}
                    </div>
                  ))}
                </div>
              </div>
            )}

            <div style={{ marginBottom: '24px' }}>
              <h3 className="section-title" style={{ marginBottom: '12px' }}>jan Lina's Examples</h3>
              <div style={{ display: 'grid', gap: '12px' }}>
                {partsOfSpeech.map(pos => (
                  <div key={pos} style={{ background: '#1a1a1a', padding: '16px', borderRadius: '12px', borderLeft: '4px solid #333' }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '8px' }}>
                      <span style={{ fontWeight: 900, color: '#444', fontSize: '0.65rem' }}>{pos.toUpperCase()}</span>
                      <button onClick={() => { onAskLina(`toki jan Lina! Can we practice using "${word.word}" as a ${pos}?`); onClose(); }} style={{ background: 'transparent', border: 'none', color: '#3b82f6', fontWeight: 'bold', cursor: 'pointer' }}>ASK JAN LINA</button>
                    </div>
                    {isLoadingExamples ? (
                      <div style={{ color: '#444', fontSize: '0.85rem' }}>Thinking...</div>
                    ) : linaExamples && linaExamples[pos] ? (
                      <p style={{ color: '#eee', fontSize: '0.95rem', lineHeight: '1.4' }}>{linaExamples[pos]}</p>
                    ) : (
                      <p style={{ color: '#555', fontSize: '0.85rem', fontStyle: 'italic' }}>Select ASK JAN LINA to generate examples with jan Lina.</p>
                    )}
                  </div>
                ))}
              </div>
            </div>

            <div style={{ marginBottom: '12px' }}>
              <h3 className="section-title" style={{ marginBottom: '8px' }}>Meanings</h3>
              <p style={{ color: '#aaa', fontSize: '0.9rem', lineHeight: '1.5' }}>{word.meanings}</p>
            </div>
          </div>
          <div style={{ padding: '20px', borderTop: '1px solid #222' }}>
            <button onClick={onClose} style={{ width: '100%', padding: '12px', background: '#333', color: 'white', border: 'none', borderRadius: '12px', fontWeight: 'bold', cursor: 'pointer' }}>✕ CLOSE</button>
          </div>
        </motion.div>
      )}
    </AnimatePresence>
  );
}

