                    <span key={n} style={{ background: '#1a1a1a', padding: '4px 8px', borderRadius: '6px', fontSize: '0.7rem', color: '#888', border: '1px solid #222' }}>{n}</span>
                  )) || <span style={{ color: '#444', fontSize: '0.75rem' }}>No neighbors listed.</span>}
