        viewBox={`0 0 100 100`}
        preserveAspectRatio="none"
      >
        <rect
          x={1.5} y={1.5}
          width={97} height={97}
          rx={8} ry={8}
          fill="none"
          stroke={color}
          strokeWidth={3}
          strokeOpacity={0.15}
        />
        <circle
          cx={50} cy={50} r={48.5}
          fill="none"
          stroke={color}
